import{_ as e,o as a,c as i,d as s}from"./index.4ce7143c.js";const o={},c={class:"adp","data-respond-to-offset":"true"},t=s('<section class="breadcrumbs"><div class="breadcrumbs-overlay"></div><div class="breadcrumbs-wrapper"><div class="breadcrumb-items"><a href="/web/" class="breadcrumb">Home</a> <span class="divider"></span> <a href="/web/coffee" class="breadcrumb">All Coffee</a> <span class="divider"></span> <a href="/web/coffee/articles" class="breadcrumb">Coffee Articles</a></div></div></section><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container"><div class="row"><div class="col-12"><div class="pimcore_area_advanced-banner-display pimcore_area_content"><div class="brick-wrapper"><div class="banner-display-block m-height-80 t-height-35 d-height-30"><div class="item bg-none" data-arrow-color=""><div class="images"><picture class="lazy"><source media="(min-width:1700px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5909/image-thumb__5909__responsive_1700_JPEG/hero-desktop-30percent-3840x1152.94143001.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5909/image-thumb__5909__responsive_3400_JPEG/hero-desktop-30percent-3840x1152.4d14fa0a.jpg 2x" data-alt="hero desktop 30percent 3840x1152"><source media="(min-width:1400px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5909/image-thumb__5909__responsive_1699_JPEG/hero-desktop-30percent-3840x1152.285a3bf1.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5909/image-thumb__5909__responsive_3398_JPEG/hero-desktop-30percent-3840x1152.cf688a2d.jpg 2x" data-alt="hero desktop 30percent 3840x1152"><source media="(min-width:1200px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5909/image-thumb__5909__responsive_1399_JPEG/hero-desktop-30percent-3840x1152.cefb2c3a.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5909/image-thumb__5909__responsive_2798_JPEG/hero-desktop-30percent-3840x1152.c287caa8.jpg 2x" data-alt="hero desktop 30percent 3840x1152"><source media="(min-width:992px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5909/image-thumb__5909__responsive_1199_JPEG/hero-desktop-30percent-3840x1152.d8475c61.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5909/image-thumb__5909__responsive_2398_JPEG/hero-desktop-30percent-3840x1152.e91e78bc.jpg 2x" data-alt="hero desktop 30percent 3840x1152"><source media="(min-width:768px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5907/image-thumb__5907__responsive_991_JPEG/hero-tablet-35percent-1982x694.8a57100d.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5907/image-thumb__5907__responsive_1982_JPEG/hero-tablet-35percent-1982x694.e354c20f.jpg 2x" data-alt="hero tablet 35percent 1982x694"><source type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5908/image-thumb__5908__responsive_767_JPEG/hero-mobile-80percent-1534x1227.9f3f11e0.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5908/image-thumb__5908__responsive_1534_JPEG/hero-mobile-80percent-1534x1227.da90dbbc.jpg 2x" data-alt="hero mobile 80percent 1534x1227"><img alt="hero desktop 30percent 3840x1152" class="optanon-category-C0002-C0004-C0005 lazyload" data-src="https://www.folgerscoffee.comhttps://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5908/image-thumb__5908__responsive_1_JPEG/hero-mobile-80percent-1534x1227.7d0ff5e0.jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5909/image-thumb__5909__responsive_1199_JPEG/hero-desktop-30percent-3840x1152.d8475c61.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5909/image-thumb__5909__responsive_2398_JPEG/hero-desktop-30percent-3840x1152.e91e78bc.jpg 2x"></picture></div></div></div></div></div></div></div></div></div></div><section class="article"><div class="section-inner"><div class="article-wrapper"><div class="article-body"><div class="article-overview-wrapper object-overview-wrapper"><div class="article-information object-information"><div class="article-name"><h1 class="heading">What is a Macchiato?</h1></div><div class="article-author"><div class="eyebrow"> By: Folgers (Folgerscoffee.com)</div></div><div class="article-description"></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p>In the world of coffee, where tradition and innovation often converge, few beverages capture the senses quite like the macchiato. A small but potent beverage, a macchiato is typically made with a shot of espresso or strong coffee and a small amount of steamed milk or foam on top. This drink has a layered look, as the milk is spooned over the espresso after it is brewed. Macchiatos are known for their strong, bold taste, and are traditionally served in small cups.\xA0\xA0</p></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper bg-cream"><div class="container-full"><div class="row"><div class="col v-align-center"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container"><div class="row"><div class="col v-align-center"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><span class="align-left eyebrow heading"></span></div></div><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h4 class="align-center color-black heading"> MACCHIATO</h4></div></div><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h3 class="align-center color-dark-red heading"> Typically made with a shot of espresso or strong coffee and a small amount of steamed milk or foam on top.</h3></div></div><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><p class="align-left heading"></p></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col-12 col-md-12 col-lg-12"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h2 class="align-left heading"> Macchiato Ingredients</h2></div></div><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p>To make a macchiato, you need just two primary ingredients: espresso, or strongly brewed coffee, and a small amount of milk.</p><p><strong>Coffee:</strong> Macchiatos are typically made with a shot of espresso but can also be crafted with strongly brewed coffee. To make at home, we recommend using <a href="/web/coffee/ground/black-silk"><strong>Folgers</strong><sup>\xAE</sup> Black Silk Ground Coffee</a>.</p><p><strong>Milk:</strong> You\u2019ll need a small amount of milk, which is often steamed but sometimes frothed. The milk-to-espresso ratio is quite low. Use any milk you like, whether that\u2019s whole milk, skim milk, or a non-dairy option.</p></div></div></div></div></div></div><div class="col-12 col-md-12 col-lg-12"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_advanced-banner-display pimcore_area_content"><div class="brick-wrapper"><div class="banner-display-block m-height-100 t-height-35 d-height-25"><div class="item bg-none" data-arrow-color=""><div class="images"><picture class="lazy"><source media="(min-width:1700px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_1700_JPEG/Body-1.4c067713.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_3400_JPEG/Body-1.d65717cb.jpg 2x" data-alt="Body 1"><source media="(min-width:1400px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_1699_JPEG/Body-1.f412101e.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_3398_JPEG/Body-1.8bd2ef93.jpg 2x" data-alt="Body 1"><source media="(min-width:1200px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_1399_JPEG/Body-1.deb2ad80.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_2798_JPEG/Body-1.652dc242.jpg 2x" data-alt="Body 1"><source media="(min-width:992px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_1199_JPEG/Body-1.57a0dfaa.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_2398_JPEG/Body-1.eab0c08e.jpg 2x" data-alt="Body 1"><source media="(min-width:768px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_991_JPEG/Body-1.28535f99.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_1982_JPEG/Body-1.1d630529.jpg 2x" data-alt="Body 1"><source type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5910/image-thumb__5910__responsive_767_JPEG/Body-1-mobile.fd8be5f9.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5910/image-thumb__5910__responsive_1534_JPEG/Body-1-mobile.ae82d761.jpg 2x" data-alt="Body 1 mobile"><img alt="Body 1" class="optanon-category-C0002-C0004-C0005 lazyload" data-src="https://www.folgerscoffee.comhttps://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5910/image-thumb__5910__responsive_1_JPEG/Body-1-mobile.ba9ce9fc.jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_1199_JPEG/Body-1.57a0dfaa.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5911/image-thumb__5911__responsive_2398_JPEG/Body-1.eab0c08e.jpg 2x"></picture></div></div></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col-12 col-md-12 col-lg-12"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h2 class="align-left heading">How to Make a Macchiato</h2></div></div><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p>Making a macchiato is very straightforward and can be done in just a few steps.\xA0</p><ol><li>Start by pulling a shot of espresso or preparing a cup of strongly brewed <a href="/web/coffee/ground"><strong>Folgers</strong> coffee</a>. Consider brewing double the typical strength you enjoy, in order to produce a strong-tasting macchiato.\xA0 </li><li>In a separate container, steam a small amount of milk until it\u2019s warm and foamy.\xA0 </li><li>Pour your prepared coffee into a small glass.\xA0</li><li>Gently add the steamed milk, creating a layered effect with the coffee on the bottom and milk on top. Alternatively, simply add the milk foam only.\xA0 </li></ol></div></div></div></div></div></div><div class="col-12 col-md-12 col-lg-12"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_advanced-banner-display pimcore_area_content"><div class="brick-wrapper"><div class="banner-display-block m-height-100 t-height-35 d-height-25"><div class="item bg-none" data-arrow-color=""><div class="images"><picture class="lazy"><source media="(min-width:1700px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_1700_JPEG/Body-2.14695975.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_3400_JPEG/Body-2.5f0f04f0.jpg 2x" data-alt="Body 2"><source media="(min-width:1400px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_1699_JPEG/Body-2.6a953545.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_3398_JPEG/Body-2.6b73095c.jpg 2x" data-alt="Body 2"><source media="(min-width:1200px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_1399_JPEG/Body-2.ef385376.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_2798_JPEG/Body-2.4cf06c66.jpg 2x" data-alt="Body 2"><source media="(min-width:992px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_1199_JPEG/Body-2.33d7d21a.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_2398_JPEG/Body-2.3493fd5f.jpg 2x" data-alt="Body 2"><source media="(min-width:768px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_991_JPEG/Body-2.f66a3451.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_1982_JPEG/Body-2.6a38e13f.jpg 2x" data-alt="Body 2"><source type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5912/image-thumb__5912__responsive_767_JPEG/Body-2-mobile.47dc7009.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5912/image-thumb__5912__responsive_1534_JPEG/Body-2-mobile.87dfc9c9.jpg 2x" data-alt="Body 2 mobile"><img alt="Body 2" class="optanon-category-C0002-C0004-C0005 lazyload" data-src="https://www.folgerscoffee.comhttps://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5912/image-thumb__5912__responsive_1_JPEG/Body-2-mobile.b6de6874.jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_1199_JPEG/Body-2.33d7d21a.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5913/image-thumb__5913__responsive_2398_JPEG/Body-2.3493fd5f.jpg 2x"></picture></div></div></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container"><div class="row"><div class="col-12 col-md-12 col-lg-12"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h2 class="align-left heading"> Popular Types of Macchiatos</h2></div></div><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p>While the classic macchiato is made with just coffee and milk, there are many ways to put a twist on the recipe to appeal to a wide range of tastes.\xA0\xA0</p><p><strong>Flavored Macchiato: </strong>Perhaps the most popular macchiato variation, a caramel macchiato features the addition of caramel syrup for a sweet and slightly buttery taste. If you\u2019re not a caramel fan, different syrups can be substituted. Vanilla, chocolate, hazelnut, and raspberry syrups are all popular additions to macchiatos.\xA0</p><p><strong>Iced Macchiato:</strong> While most macchiatos are served hot, iced macchiatos are a refreshing option. Espresso and milk are poured over ice, creating a satisfying drink, perfect for warm weather.\xA0</p><p><strong>Macchiato Frappe:</strong> This blended, frozen version of the macchiato is a dessert-like treat for those who desire something cold. Folgers <a href="/web/coffee/recipes/iced-coffee/caramel-macchiato-frappe">Caramel Macchiato Frappe</a> is a truly delicious option.\xA0</p><p>Whether you prefer the simplicity of a classic macchiato or one of these creative interpretations, there\u2019s a macchiato to suit most coffee drinkers. Home baristas can experiment with different syrup flavors and types of milk for even more variety in their beverages.\xA0</p></div></div></div></div></div></div><div class="col-12 col-md-12 col-lg-12"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_advanced-banner-display pimcore_area_content"><div class="brick-wrapper"><div class="banner-display-block m-height-100 t-height-35 d-height-25"><div class="item bg-none" data-arrow-color=""><div class="images"><picture class="lazy"><source media="(min-width:1700px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_1700_JPEG/Body-3.a99e7844.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_3400_JPEG/Body-3.5ef9d455.jpg 2x" data-alt="Body 3"><source media="(min-width:1400px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_1699_JPEG/Body-3.e0bb37a9.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_3398_JPEG/Body-3.8b721ab7.jpg 2x" data-alt="Body 3"><source media="(min-width:1200px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_1399_JPEG/Body-3.34193208.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_2798_JPEG/Body-3.76e7cf17.jpg 2x" data-alt="Body 3"><source media="(min-width:992px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_1199_JPEG/Body-3.25c495a8.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_2398_JPEG/Body-3.00d16b63.jpg 2x" data-alt="Body 3"><source media="(min-width:768px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_991_JPEG/Body-3.622a417d.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_1982_JPEG/Body-3.f55735b2.jpg 2x" data-alt="Body 3"><source type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5914/image-thumb__5914__responsive_767_JPEG/Body-3-mobile.926a76ba.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5914/image-thumb__5914__responsive_1534_JPEG/Body-3-mobile.611346a8.jpg 2x" data-alt="Body 3 mobile"><img alt="Body 3" class="optanon-category-C0002-C0004-C0005 lazyload" data-src="https://www.folgerscoffee.comhttps://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5914/image-thumb__5914__responsive_1_JPEG/Body-3-mobile.5f281af3.jpg" srcset="https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_1199_JPEG/Body-3.25c495a8.jpg 1x, https://www.folgerscoffee.com/folgers/articles/What%20is%20a%20Macchiato/5915/image-thumb__5915__responsive_2398_JPEG/Body-3.00d16b63.jpg 2x"></picture></div></div></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container"><div class="row"><div class="col-12 col-md-12 col-lg-12"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h2 class="align-left heading">Tips for Making the Perfect Macchiato</h2></div></div><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><ul><li>Start with freshly brewed, high-quality coffee (or espresso) for the best flavor.\xA0 </li><li>Steam your milk gently, heating to a temperature where it\u2019s warm, but not scalding (around 140\xB0F to 150\xB0F).\xA0 </li><li>Pour the steamed milk gently into your prepared coffee to create a layered effect. The milk should sit on top.\xA0 </li><li>If you prefer flavored macchiatos, add your choice of syrup to the milk before pouring.\xA0 </li><li>Adjust the amount of milk and flavorings to suit your personal taste.\xA0 </li><li>The macchiato is a delicious drink that perfectly balances the rich flavor of espresso with the creaminess of milk. Whether you prefer the classic or the sweet indulgence of caramel flavoring, the macchiato is a masterpiece that\u2019s adaptable to your personal preference.\xA0 </li></ul></div></div></div></div></div></div></div></div></div></div></div></div></div></section>',3),r=[t];function l(d,p){return a(),i("main",c,r)}var m=e(o,[["render",l]]);export{m as default};
